import React, { useEffect, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { API, showError, timestamp2string } from '../../helpers';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '../../components/ui/table';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '../../components/ui/select';
import { Input } from '../../components/ui/input';
import {
  Search,
  ChevronLeft,
  ChevronRight,
} from 'lucide-react';

const ITEMS_PER_PAGE = 10;

const BillingPage = () => {
  const { t } = useTranslation();
  const [orders, setOrders] = useState([]);
  const [page, setPage] = useState(0);
  const [loading, setLoading] = useState(false);
  const [typeFilter, setTypeFilter] = useState('all');
  const [statusFilter, setStatusFilter] = useState('all');
  const [searchKeyword, setSearchKeyword] = useState('');

  useEffect(() => {
    loadOrders();
  }, [page]); // eslint-disable-line react-hooks/exhaustive-deps

  const loadOrders = async () => {
    setLoading(true);
    try {
      const res = await API.get(`/api/order/self?p=${page}`);
      if (res.data.success) {
        setOrders(res.data.data || []);
      } else {
        showError(res.data.message);
      }
    } catch (err) {
      showError(t('console.billing.load_failed'));
    }
    setLoading(false);
  };

  // Client-side filtering
  const filteredOrders = orders.filter((order) => {
    if (typeFilter !== 'all') {
      if (String(order.type) !== typeFilter) return false;
    }
    if (statusFilter !== 'all') {
      if (String(order.status) !== statusFilter) return false;
    }
    if (searchKeyword) {
      if (!order.order_no?.toLowerCase().includes(searchKeyword.toLowerCase())) return false;
    }
    return true;
  });

  // Type tag rendering (Figma: 订阅=blue, 加油包=green)
  const renderTypeTag = (type) => {
    const isBooster = type === 5;
    if (isBooster) {
      return (
        <span className='inline-flex items-center h-6 px-2 text-xs font-medium bg-[#f6ffed] border border-[#b7eb8f] text-[#52c41a]'>
          加油包
        </span>
      );
    }
    const typeLabels = { 1: '新订阅', 2: '续费', 3: '升级', 4: '降级' };
    return (
      <span className='inline-flex items-center h-6 px-2 text-xs font-medium bg-[#f0f5ff] border border-[#bdceff] text-[#4362ff]'>
        {typeLabels[type] || '订阅'}
      </span>
    );
  };

  // Status badge rendering (Figma: 已支付=green dot, 已过期=gray dot)
  const renderStatusBadge = (status) => {
    switch (status) {
      case 2:
        return (
          <span className='inline-flex items-center gap-1.5 text-sm'>
            <span className='w-1.5 h-1.5 rounded-full bg-[#52c41a]' />
            <span className='text-[#090e1a]'>已支付</span>
          </span>
        );
      case 1:
        return (
          <span className='inline-flex items-center gap-1.5 text-sm'>
            <span className='w-1.5 h-1.5 rounded-full bg-[#faad14]' />
            <span className='text-[#8c6d1f]'>待支付</span>
          </span>
        );
      case 4:
        return (
          <span className='inline-flex items-center gap-1.5 text-sm'>
            <span className='w-1.5 h-1.5 rounded-full bg-[#9eacbf]' />
            <span className='text-[#9eacbf]'>已取消</span>
          </span>
        );
      case 3:
        return (
          <span className='inline-flex items-center gap-1.5 text-sm'>
            <span className='w-1.5 h-1.5 rounded-full bg-[#9eacbf]' />
            <span className='text-[#9eacbf]'>已退款</span>
          </span>
        );
      case 5:
        return (
          <span className='inline-flex items-center gap-1.5 text-sm'>
            <span className='w-1.5 h-1.5 rounded-full bg-[#9eacbf]' />
            <span className='text-[#9eacbf]'>已过期</span>
          </span>
        );
      default:
        return (
          <span className='inline-flex items-center gap-1.5 text-sm'>
            <span className='w-1.5 h-1.5 rounded-full bg-[#9eacbf]' />
            <span className='text-[#9eacbf]'>未知</span>
          </span>
        );
    }
  };

  const renderContent = (order) => {
    const typeLabels = { 1: '新订阅', 2: '续费', 3: '升级', 4: '降级', 5: '加油包' };
    return typeLabels[order.type] || `订单 #${order.id}`;
  };

  return (
    <div className='flex flex-col min-h-0'>
      {/* Page header */}
      <div className='bg-white px-6 py-5 border-b border-[#e1e7ef]'>
        <h1 className='text-2xl font-medium text-[#090e1a] leading-8'>账单记录</h1>
        <p className='text-base text-[#65758b] mt-1'>从免费试用开始，按需升级</p>
      </div>

      {/* Content */}
      <div className='flex-1 overflow-y-auto p-6'>
        <div className='bg-white border border-[#e1e7ef]'>
          {/* Filter bar */}
          <div className='flex items-center gap-3 px-6 py-4 border-b border-[#e1e7ef]'>
            <Select value={typeFilter} onValueChange={setTypeFilter}>
              <SelectTrigger className='w-[140px] h-9 border-[#e1e7ef] text-sm'>
                <SelectValue placeholder='全部类型' />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value='all'>全部类型</SelectItem>
                <SelectItem value='1'>新订阅</SelectItem>
                <SelectItem value='2'>续费</SelectItem>
                <SelectItem value='3'>升级</SelectItem>
                <SelectItem value='4'>降级</SelectItem>
                <SelectItem value='5'>加油包</SelectItem>
              </SelectContent>
            </Select>

            <Select value={statusFilter} onValueChange={setStatusFilter}>
              <SelectTrigger className='w-[140px] h-9 border-[#e1e7ef] text-sm'>
                <SelectValue placeholder='全部状态' />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value='all'>全部状态</SelectItem>
                <SelectItem value='1'>待支付</SelectItem>
                <SelectItem value='2'>已支付</SelectItem>
                <SelectItem value='3'>已退款</SelectItem>
                <SelectItem value='4'>已取消</SelectItem>
                <SelectItem value='5'>已过期</SelectItem>
              </SelectContent>
            </Select>

            <div className='relative flex-1 max-w-[280px]'>
              <Search className='absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-[#9eacbf]' />
              <Input
                placeholder='搜索订单号'
                className='pl-9 h-9 border-[#e1e7ef] text-sm'
                value={searchKeyword}
                onChange={(e) => setSearchKeyword(e.target.value)}
              />
            </div>
          </div>

          {/* Table */}
          <div className='px-6'>
            <Table>
              <TableHeader>
                <TableRow className='border-b border-[#e1e7ef] hover:bg-transparent'>
                  <TableHead className='bg-[#f8fafc] text-[#090e1a] font-semibold text-sm h-11'>订单号</TableHead>
                  <TableHead className='bg-[#f8fafc] text-[#090e1a] font-semibold text-sm h-11'>时间</TableHead>
                  <TableHead className='bg-[#f8fafc] text-[#090e1a] font-semibold text-sm h-11'>类型</TableHead>
                  <TableHead className='bg-[#f8fafc] text-[#090e1a] font-semibold text-sm h-11'>内容</TableHead>
                  <TableHead className='bg-[#f8fafc] text-[#090e1a] font-semibold text-sm h-11'>金额</TableHead>
                  <TableHead className='bg-[#f8fafc] text-[#090e1a] font-semibold text-sm h-11'>状态</TableHead>
                  <TableHead className='bg-[#f8fafc] text-[#090e1a] font-semibold text-sm h-11 text-right'>操作</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {loading ? (
                  <TableRow>
                    <TableCell colSpan={7} className='text-center py-12 text-[#9eacbf]'>
                      加载中...
                    </TableCell>
                  </TableRow>
                ) : filteredOrders.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={7} className='text-center py-12 text-[#9eacbf]'>
                      暂无账单记录
                    </TableCell>
                  </TableRow>
                ) : (
                  filteredOrders.map((order) => (
                    <TableRow key={order.id} className='border-b border-[#e1e7ef] hover:bg-[#f8fafc]'>
                      <TableCell className='text-sm text-[#090e1a] font-mono'>
                        {order.order_no || `#${order.id}`}
                      </TableCell>
                      <TableCell className='text-sm text-[#090e1a]'>
                        {timestamp2string(order.created_time)}
                      </TableCell>
                      <TableCell>
                        {renderTypeTag(order.type)}
                      </TableCell>
                      <TableCell className='text-sm text-[#090e1a]'>
                        {renderContent(order)}
                      </TableCell>
                      <TableCell className='text-sm text-[#090e1a] font-medium'>
                        ¥{(order.amount_cents / 100).toFixed(2)}
                      </TableCell>
                      <TableCell>
                        {renderStatusBadge(order.status)}
                      </TableCell>
                      <TableCell className='text-right'>
                        <button className='text-sm text-[#4362ff] hover:underline border-0 bg-transparent cursor-pointer'>
                          详情
                        </button>
                      </TableCell>
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          </div>

          {/* Pagination */}
          <div className='flex items-center justify-between px-6 py-3 border-t border-[#e1e7ef]'>
            <span className='text-sm text-[#9eacbf]'>
              第 {page + 1} 页
            </span>
            <div className='flex items-center gap-1'>
              <button
                className='w-8 h-8 flex items-center justify-center border border-[#e1e7ef] hover:bg-[#f8fafc] disabled:opacity-40 disabled:cursor-not-allowed transition-colors bg-white cursor-pointer'
                disabled={page === 0}
                onClick={() => setPage((p) => Math.max(0, p - 1))}
              >
                <ChevronLeft className='h-4 w-4 text-[#344256]' />
              </button>
              <button className='w-8 h-8 flex items-center justify-center border border-[#4362ff] bg-white text-[#4362ff] text-sm font-medium cursor-default'>
                {page + 1}
              </button>
              <button
                className='w-8 h-8 flex items-center justify-center border border-[#e1e7ef] hover:bg-[#f8fafc] disabled:opacity-40 disabled:cursor-not-allowed transition-colors bg-white cursor-pointer'
                disabled={orders.length < ITEMS_PER_PAGE}
                onClick={() => setPage((p) => p + 1)}
              >
                <ChevronRight className='h-4 w-4 text-[#344256]' />
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default BillingPage;
